import React from 'react';
import { ChipGroup, Chip } from '@salutejs/plasma-web';
export function App() {
    return (
        <ChipGroup>
            {Array(5)
                .fill(true)
                .map((_, i) => (
                    <Chip text={`Chip ${i}`} />
                ))}
        </ChipGroup>
    );
}

import React from 'react';
import { ChipGroup, Chip } from '@salutejs/plasma-web';
export function App() {
    return (
        <div>
            <ChipGroup size="s" view="secondary">
                {Array(5)
                    .fill(true)
                    .map((_, i) => (
                        <Chip text={`Chip ${i}`} />
                    ))}
            </ChipGroup>
            <ChipGroup isCommonChipStyles={false}>
                <Chip size="m" text="Default" />
                <Chip size="s" text="Secondary" view="secondary" />
                <Chip size="xs" text="Accent" view="accent" />
            </ChipGroup>
        </div>
    );
}

